const item = $input.first().json;

function bar(pct) {
  const c = pct >= 100 ? '#16a34a' : pct >= 70 ? '#d97706' : '#dc2626';
  return `<div style="background:#e2e8f0;border-radius:99px;height:8px;overflow:hidden;margin-top:8px"><div style="width:${Math.min(pct,100)}%;height:100%;background:${c};border-radius:99px"></div></div>`;
}
function c(pct) { return pct >= 100 ? '#16a34a' : pct >= 70 ? '#d97706' : '#dc2626'; }
function ini(name) { return name.split(' ').map(n=>n[0]).join('').slice(0,2).toUpperCase(); }

// ── Objetivos: espaço real entre nome e %
const objRows = (item.objective_progress || []).map(o => `
  <div style="margin-bottom:16px">
    <div style="display:flex;justify-content:space-between;align-items:center">
      <span style="font-size:13px;font-weight:600;color:#1a2035;line-height:1.3;padding-right:16px">${o.title}</span>
      <span style="font-size:13px;font-weight:700;color:${c(o.result_pct)};white-space:nowrap;flex-shrink:0">${o.result_pct}%</span>
    </div>${bar(o.result_pct)}
  </div>`).join('');

// ── Ranking item
function rankItem(r, rank, isMe) {
  const brd = isMe ? 'border:2px solid #93c5fd;background:#eff6ff' : 'border:1px solid #e2e8f0;background:#f8faff';
  const avatar = r.avatar_url
    ? `<img src="${r.avatar_url}" style="width:38px;height:38px;border-radius:50%;object-fit:cover;flex-shrink:0" />`
    : `<div style="width:38px;height:38px;border-radius:50%;background:linear-gradient(135deg,#3b82f6,#1e40af);color:#fff;font-size:13px;font-weight:700;display:inline-flex;align-items:center;justify-content:center;flex-shrink:0">${ini(r.full_name)}</div>`;
  return `
  <div style="${brd};border-radius:10px;padding:10px 16px;margin-bottom:8px;display:flex;align-items:center;gap:12px">
    <span style="min-width:30px;font-size:16px;font-weight:800;color:#1e40af;flex-shrink:0;text-align:center">#${rank}</span>
    ${avatar}
    <div style="flex:1;min-width:0;padding-left:4px">
      <div style="font-size:13px;font-weight:600;color:#1a2035;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">
        ${r.full_name}${isMe?' <span style="font-size:10px;background:#dbeafe;color:#1d4ed8;padding:1px 6px;border-radius:4px">Você</span>':''}
      </div>
      <div style="font-size:11px;color:#94a3b8;margin-top:2px">${r.sector||'Sem setor'}</div>
    </div>
    <span style="font-size:15px;font-weight:700;color:#1e40af;flex-shrink:0;padding-left:12px">${r.result_pct}%</span>
  </div>`;
}

// ── Minha posição
const myData = (item.top5_ranking || []).find(r => r.user_id === item.user_id) || {
  user_id: item.user_id, full_name: item.to_name, sector: '', avatar_url: null, result_pct: item.user_progress
};
const myCard = rankItem(myData, item.user_rank, true);

// ── OKRs DO PRÓPRIO USUÁRIO
const okrRows = (item.user_okrs || []).map(o => `
  <div style="padding:12px 0;border-bottom:1px solid #f1f5f9">
    <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:16px;margin-bottom:8px">
      <span style="font-size:13px;font-weight:500;color:#1a2035;line-height:1.4;padding-right:8px">${o.title}</span>
      <span style="font-size:14px;font-weight:700;color:${c(o.result_pct)};flex-shrink:0">${o.result_pct}%</span>
    </div>${bar(o.result_pct)}
  </div>`).join('');

const now = new Date();
const mon = new Date(now); mon.setDate(now.getDate()-((now.getDay()+6)%7));
const sun = new Date(mon); sun.setDate(mon.getDate()+6);
const fmt = d => d.toLocaleDateString('pt-BR',{day:'2-digit',month:'short'});

const html = `<!DOCTYPE html><html lang="pt-BR"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"></head>
<body style="margin:0;padding:0;background:#f0f4f8;font-family:'Segoe UI',Arial,sans-serif;color:#1a2035">
<div style="max-width:640px;margin:32px auto;background:#fff;border-radius:16px;overflow:hidden;box-shadow:0 4px 32px rgba(30,64,175,.10)">

  <div style="background:linear-gradient(135deg,#1e40af 0%,#3b82f6 60%,#06b6d4 100%);padding:36px 40px 28px;text-align:center">
    <div style="margin-bottom:16px"><span style="font-size:22px;font-weight:700;color:#fff">🎯 WenKey</span></div>
    <span style="display:inline-block;background:rgba(255,255,255,.15);border:1px solid rgba(255,255,255,.3);color:#e0f2fe;font-size:11px;font-weight:600;letter-spacing:1.5px;text-transform:uppercase;padding:4px 12px;border-radius:999px;margin-bottom:10px">✉ Relatório Semanal</span>
    <h1 style="color:#fff;font-size:26px;font-weight:700;margin:0">Seus Indicadores de OKR</h1>
    <p style="margin-top:8px;color:rgba(255,255,255,.75);font-size:14px">${item.quarter_name} · ${fmt(mon)} – ${fmt(sun)}</p>
  </div>

  <div style="padding:28px 40px 0">
    <h2 style="font-size:20px;font-weight:600;color:#1a2035;margin:0">Olá, ${item.to_name} 👋</h2>
    <p style="margin-top:6px;font-size:14px;color:#64748b;line-height:1.6">Aqui está um resumo dos seus indicadores e do desempenho da equipe no quarter atual.</p>
  </div>

  <p style="padding:24px 40px 10px;font-size:11px;font-weight:700;letter-spacing:1.2px;text-transform:uppercase;color:#94a3b8;margin:0">Seus números desta semana</p>
  <div style="padding:0 40px 8px;display:flex;gap:12px">
    <div style="flex:1;background:#f8faff;border:1px solid #e2e8f0;border-radius:12px;padding:18px 16px;text-align:center">
      <div style="font-size:32px;font-weight:700;color:#1e40af;line-height:1">${item.active_objectives}</div>
      <div style="margin-top:6px;font-size:11px;color:#64748b;text-transform:uppercase">Objetivos Ativos</div>
    </div>
    <div style="flex:1;background:#f8faff;border:1px solid #e2e8f0;border-radius:12px;padding:18px 16px;text-align:center">
      <div style="font-size:32px;font-weight:700;color:#1e40af;line-height:1">${item.active_okrs}</div>
      <div style="margin-top:6px;font-size:11px;color:#64748b;text-transform:uppercase">OKRs Ativos</div>
    </div>
    <div style="flex:1;background:#f8faff;border:1px solid #e2e8f0;border-radius:12px;padding:18px 16px;text-align:center">
      <div style="font-size:32px;font-weight:700;color:#16a34a;line-height:1">${item.user_progress}%</div>
      <div style="margin-top:6px;font-size:11px;color:#64748b;text-transform:uppercase">Progresso Quarter</div>
    </div>
  </div>

  <p style="padding:24px 40px 10px;font-size:11px;font-weight:700;letter-spacing:1.2px;text-transform:uppercase;color:#94a3b8;margin:0">Progresso por Objetivo</p>
  <div style="padding:0 40px 8px">
    <div style="background:#f8faff;border:1px solid #e2e8f0;border-radius:12px;padding:20px">${objRows}</div>
  </div>

  <p style="padding:24px 40px 10px;font-size:11px;font-weight:700;letter-spacing:1.2px;text-transform:uppercase;color:#94a3b8;margin:0">Sua posição no ranking</p>
  <div style="padding:0 40px">${myCard}</div>

  <p style="padding:24px 40px 10px;font-size:11px;font-weight:700;letter-spacing:1.2px;text-transform:uppercase;color:#94a3b8;margin:0">Meus OKRs em Destaque</p>
  <div style="padding:0 40px">${okrRows}</div>

  <div style="margin-top:32px;padding:24px 40px;background:#f8faff;border-top:1px solid #e2e8f0;text-align:center">
    <div style="font-size:16px;font-weight:800;color:#1e40af;margin-bottom:8px">WenKey</div>
    <p style="font-size:11px;color:#94a3b8;line-height:1.6">© 2026 WenKey. Todos os direitos reservados.</p>
  </div>

</div></body></html>`;

return [{ json: { ...item, html_body: html, subject: `📊 Seu Relatório Semanal de OKRs – ${item.quarter_name}` } }];
